module multi_io_module(
  input [3:0] in1,
  input [2:0] in2,
  input in3,
  input clk,
  output [1:0] out1,
  output out2,
  output [2:0] out3,
  output out4
);

    wire _n01 = in1[1:0][0] ^ in2[0];
  wire _c01 = in1[1:0][0] & in2[0];
  wire _n02 = in1[1:0][1] ^ in2[1] ^ _c01;
  wire _c02 = (in1[1:0][1] & in2[1]) | (in1[1:0][1] & _c01) | (in2[1] & _c01);
  wire _n03 = in1[1:0][2] ^ in2[2] ^ _c02;
  wire _c03 = (in1[1:0][2] & in2[2]) | (in1[1:0][2] & _c02) | (in2[2] & _c02);
  wire _n04 = in1[1:0][3] ^ in2[3] ^ _c03;
  wire _c04 = (in1[1:0][3] & in2[3]) | (in1[1:0][3] & _c03) | (in2[3] & _c03);
  assign out1 = {_n01, _n02, _n03, _n04};
  assign out2 = in1[0] ^ in3;
  assign out3 = {in1, in2};
  assign out4 = in2 & in3;

endmodule
